801	/// Bare `prettyWfErrorReport` rendering (Wellformedness.hs:118-125) —
802	/// the grouped topic blocks WITHOUT the `/* WARNING ... */` comment
803	/// wrapper.  Shared by `format_wf_block` (batch theory output) and the
804	/// interactive server's `ppInteractive` console echo of the report at
805	/// theory-load time (Web/Dispatch.hs:149-209, see line 187,200-209).
806	// grouped by topic; OUTPUT order driven by the topic_order Vec, map keyed only;
807	// std kept (byte-inert) — iteration order never reaches output.
808	#[allow(clippy::disallowed_types)]
809	pub fn render_wf_error_report(report: &[tamarin_parser::wf::WfError]) -> String {
810	    let mut out = String::new();
811	    // Group by topic, preserving FIRST-APPEARANCE order — mirrors HS's
812	    // `groupOn fst` over a left-to-right concatMap-over-checks.
813	    let mut topic_order: Vec<&str> = Vec::new();
814	    let mut grouped: std::collections::HashMap<&str, Vec<&str>> =
815	        std::collections::HashMap::new();
816	    for e in report {
817	        if !grouped.contains_key(e.topic.as_str()) {
818	            topic_order.push(e.topic.as_str());
819	        }
820	        grouped.entry(e.topic.as_str()).or_default().push(&e.message);
821	    }
822	    for (i, topic) in topic_order.iter().enumerate() {
823	        let msgs = &grouped[topic];
824	        if i > 0 { out.push('\n'); }
825	        // HS `prettyWfErrorReport` (Wellformedness.hs:118-125) groups by
826	        // topic and renders each group as
827	        //   `text topic $-$ (nest 2 . vcat . intersperse (text "") $ bodies)`
828	        // — the underlineTopic header ONCE per group, then the 2-space-nested
829	        // bodies separated by a 2-space blank line.  Most RS checks already
830	        // pre-render the FULL block (header + indent) into a single per-topic
831	        // message, and we concatenate those as-is (legacy path, unchanged).
832	        //
833	        // Some checks emit one HEADER-LESS body per offending rule (so the
834	        // summary's `length rep` WARNING count stays HS-faithful,
835	        // Batch.hs:87-316, see line 245), all sharing one topic.  These are assembled HS-style
836	        // (`prettyWfErrorReport`, Wellformedness.hs:118-125): the topic header
837	        // (+ any "reasons" preamble that HS folds into the topic string) ONCE,
838	        // then the per-rule bodies joined by the `intersperse (text "")`
839	        // 2-space blank separator.  Other (single-entry) topics keep baking
840	        // their full block into the message (default path below).
841	        if let Some(preamble) = wf_headerless_preamble(topic) {
842	            out.push_str(&preamble);
843	            out.push_str(&msgs.join("\n  \n"));
844	            out.push('\n');
845	        } else {
846	            for (j, m) in msgs.iter().enumerate() {
847	                if j > 0 { out.push('\n'); }
848	                out.push_str(m);
849	                if !m.ends_with('\n') { out.push('\n'); }
850	            }
851	        }
852	    }
853	    out
854	}
855	
856	/// For the WF topics whose checks emit one header-less body per finding,
857	/// return the byte-exact preamble that `prettyWfErrorReport` prints ONCE
858	/// before the group's bodies: the `underlineTopic` header, plus the blank
859	/// line HS's `$-$`/topic-string folds in, plus (for the sort-clash topic)
860	/// the "Possible reasons" paragraph that HS appends to the topic string
861	/// (Wellformedness.hs:258-273).  Returns `None` for single-entry topics,
862	/// which bake their full block into the message (default path).
863	fn wf_headerless_preamble(topic: &str) -> Option<String> {
864	    use tamarin_parser::wf::underline_topic;
865	    match topic {
866	        // SAPIC-process wellformedness errors (HS `toWfErrorReport`,
867	        // Warnings.hs:23-26).  Unlike the other topics, HS does NOT underline
868	        // this one — `prettyWfErrorReport` renders it as a bare `text topic`
869	        // (Wellformedness.hs:118-125, see line 124).  So the per-error bodies (each
870	        // `"  Variable bound twice: x."`) sit directly under a plain header.
871	        "Wellformedness-error in Process" => Some(format!("{topic}\n")),
872	        "Unbound variables" | "Special facts" => {
873	            Some(format!("{}\n", underline_topic(topic)))
874	        }
875	        // Corpus-validated: the batch pipeline prints a blank line after this
876	        // topic's underline (csf23-subterms/ParserTests), unlike Unbound
877	        // variables, whose corpus blocks have none.
878	        "Reserved names" => Some(format!("{}\n\n", underline_topic(topic))),
879	        // The per-formula report topics come from the clean parser-level
880	        // checker as header-less bodies; HS underlines each and separates the
881	        // header from the body with a blank line (`underlineTopic $-$ body`).
882	        "Quantifier sorts" | "Formula terms" | " Formula guardedness"
883	        | "Check presence of the --prove/--lemma arguments in theory"
884	        | "Facts occur in the left-hand-side but not in any right-hand-side " => {
885	            Some(format!("{}\n\n", underline_topic(topic)))
886	        }
887	        "Variable with mismatching sorts or capitalization" => {
888	            Some(format!(
889	                "{}\nPossible reasons:\n\
890	                 1. Identifiers are case sensitive, i.e.,\
891	                 'x' and 'X' are considered to be different.\n\
892	                 2. The same holds for sorts:, \
893	                 i.e., '$x', 'x', and '~x' are considered to be different.\n\n",
894	                underline_topic(topic)))
895	        }
896	        _ => None,
897	    }
898	}
899	
900	/// HS `ppNonEmptyList' name pp xs = (keyword_ name <->) . fsep $
901	/// punctuate comma (map pp xs)` (Term/Maude/Signature.hs:229-231).
902	/// `<->` is HughesPJ `<+>` (beside-with-space), and `fsep` is the
903	/// fill-paragraph combinator, so the wrap decisions must come from the
904	/// ported HughesPJ Doc engine (LINE_LENGTH=110, RIBBON=73) — not a
905	/// hand-rolled greedy fill at a guessed width.  Route through `pretty_hpj`.
906	fn wrap_with_lead<S: AsRef<str>>(lead: &str, items: &[S]) -> String {
907	    use crate::pretty_hpj::{self as hpj, Doc};
908	    if items.is_empty() { return String::new(); }
909	    let docs: Vec<Doc> = items.iter().map(Doc::text).collect();
910	    let body = hpj::fsep(hpj::punctuate(Doc::char(','), docs));
911	    // HS `ppNonEmptyList' name = (keyword_ name <->) . fsep`
912	    // (Term/Maude/Signature.hs:220-247, see line 229) — the `builtins:`/`functions:` lead is a
913	    // keyword.  `keyword_` is the identity in plain mode, so `--prove` is
914	    // unchanged.
915	    hpj::keyword_(lead).beside_sp(body).render()
916	}
917	
