import glob, gzip, re, subprocess

def wf_block(text):
    out=[]; f=False
    for line in text.split('\n'):
        if line=='/* All wellformedness checks were successful. */':
            out.append(line); continue
        if line=='WARNING: the following wellformedness checks failed!':
            f=True
        if f:
            out.append(line)
            if line=='*/': f=False
    return out

topics=['Unbound variables','Special facts']
# For each topic, count blocks where underline is followed by blank vs non-blank.
stats={t:{'blank':0,'nonblank':0,'blank_files':[],'nonblank_files':[]} for t in topics}
for fn in glob.glob('*.full.gz'):
    try:
        txt=gzip.open(fn).read().decode('utf-8','replace')
    except Exception:
        continue
    lines=wf_block(txt)
    for i,l in enumerate(lines):
        if l in topics:
            # next line should be underline of '=' 
            if i+1<len(lines) and re.fullmatch(r'=+', lines[i+1] or ''):
                nxt = lines[i+2] if i+2<len(lines) else ''
                if nxt.strip()=='':
                    stats[l]['blank']+=1; stats[l]['blank_files'].append(fn)
                else:
                    stats[l]['nonblank']+=1; stats[l]['nonblank_files'].append(fn)
for t in topics:
    s=stats[t]
    print(f"=== {t} ===  blank-after-underline={s['blank']}  NONblank={s['nonblank']}")
    if s['nonblank']:
        print("   NONBLANK sample files:", s['nonblank_files'][:5])
EOF

