/// For the WF topics whose checks emit one header-less body per finding,
/// return the byte-exact preamble that `prettyWfErrorReport` prints ONCE
/// before the group's bodies: the `underlineTopic` header plus the blank
/// line HS's `$-$` folds in between the header and the first body
/// (Wellformedness.hs:118-125).  Returns `None` for single-entry topics,
/// which bake their full block into the message (default path).
fn wf_headerless_preamble(topic: &str) -> Option<String> {
    use tamarin_parser::wf::underline_topic;
    match topic {
        // SAPIC-process wellformedness errors (HS `toWfErrorReport`,
        // Warnings.hs:23-26).  Unlike the other topics, HS does NOT underline
        // this one — `prettyWfErrorReport` renders it as a bare `text topic`
        // (Wellformedness.hs:118-125, see line 124).  So the per-error bodies (each
        // `"  Variable bound twice: x."`) sit directly under a plain header.
        "Wellformedness-error in Process" => Some(format!("{topic}\n")),
        // Header-less-body topics: HS underlines each and separates the header
        // from the first body with a blank line (`underlineTopic $-$ body`,
        // Wellformedness.hs:118-125).  The "mismatching sorts" body already
        // carries its own "Possible reasons:" preamble from the checker
        // (Wellformedness.hs:258-273), so the assembly supplies only the
        // underline and the blank line here — never a second copy.
        "Unbound variables"
        | "Special facts"
        | "Reserved names"
        | "Variable with mismatching sorts or capitalization"
        | "Quantifier sorts"
        | "Formula terms"
        | " Formula guardedness"
        | "Lemma annotations"
        | "Check presence of the --prove/--lemma arguments in theory"
        | "Facts occur in the left-hand-side but not in any right-hand-side " => {
            Some(format!("{}\n\n", underline_topic(topic)))
        }
        _ => None,
    }
}

